-- Strip the appended "Vocabulary: ..." sentence from narratives_v2.claim_en.
--
-- The loaded vocabulary already renders as its own chip row on the narrative
-- card (FrictionNodeNarrativeCards.tsx, sourced from framing_keywords), so
-- repeating it inside the claim prose duplicated it on screen.
--
-- Only the vocabulary SENTENCE is removed; prose that follows it (the
-- "Prescription: ..." clause on 43 rows) is preserved.
--
-- EN only. claim_de still carries 81 "Vokabular:" lines - separate pass.

BEGIN;

UPDATE narratives_v2 SET claim_en = 'Democratic-defense framing (German and Western mainstream) treats the AfD as a radical or extremist force whose classification by the domestic-intelligence service, the "Brandmauer" against cooperation, scrutiny of its access to office and state secrets and a possible ban are legitimate defences of the constitutional order.', updated_at = NOW() WHERE id = 'afd_democratic_defense';
UPDATE narratives_v2 SET claim_en = 'Exclusion-critique framing (voiced by the party and by sympathetic commentary) holds that the firewall, the intelligence classification and moves toward a ban disenfranchise millions of voters, amount to establishment overreach and threaten free speech, and that the party should be treated as a normal democratic actor.', updated_at = NOW() WHERE id = 'afd_exclusion_undemocratic';
UPDATE narratives_v2 SET claim_en = 'Counter-framing (Russian state press) presents German measures against the AfD as political persecution and censorship by a state that lectures others on democracy. Moscow favours direct dealing with national forces over Brussels-aligned establishments, so it amplifies the polarisation and the anti-establishment case — adversarial to the German mainstream rather than an endorsement of the party''s programme.', updated_at = NOW() WHERE id = 'afd_persecution_kremlin';
UPDATE narratives_v2 SET claim_en = 'Restraint framing (Russian state press + Western contrarian + Global South + Hungarian-aligned EU) treats Western aid as proxy-war escalation that delays inevitable settlement, wastes taxpayer money increasingly diverted from domestic priorities, and risks direct NATO-Russia confrontation by supplying longer-range weapons and authorising their use inside Russia. Coverage emphasises the corruption risk in aid pipelines, the ineffectiveness of escalating weapons categories in changing the battlefield, Ukrainian losses and recruitment shortages, growing European public fatigue, and the strain on US bipartisan support. Prescription: pause and reassess aid, condition it on negotiated outcomes, prevent direct NATO-Russia escalation, redirect funds to domestic priorities.', updated_at = NOW() WHERE id = 'aid_as_escalation_and_proxy';
UPDATE narratives_v2 SET claim_en = 'Pro-aid framing (Ukrainian press + Western mainstream + Eastern European hawks) treats Western military, economic, and financial assistance as both moral imperative and strategic necessity. Coverage tracks weapons deliveries (HIMARS, ATACMS, Storm Shadow, Taurus debates, F-16 deployment, Patriot replenishment), financial mechanisms (ERA loan from windfall profits on frozen Russian assets, Ukraine Facility, REPO Act seizure provisions, European Peace Facility), and the growing defense-industrial partnership (Rheinmetall-Ukraine joint ventures, Czech ammunition initiative, BAE local production). Prescription: scale all three channels; remove restrictions on Western weapons use; seize frozen sovereign assets for Ukrainian reconstruction; build long-term defense-industrial capacity in Ukraine.', updated_at = NOW() WHERE id = 'aid_sustains_defense';
UPDATE narratives_v2 SET claim_en = 'Environmental-and-climate framing (Western/green press plus climate-science reporting) treats the Arctic as a warning system and a victim: record-low sea ice, accelerating melt and thawing permafrost are a planetary climate signal, while opening the ice to drilling, mining and shipping compounds the damage through oil-spill risk, black carbon and biodiversity loss. It is the pro-development camp''s own critics -- the same outlets that report the resource boom also sound the alarm -- so publisher alone cannot separate the stances; framing keywords do.', updated_at = NOW() WHERE id = 'arctic_drilling_environmental_alarm';
UPDATE narratives_v2 SET claim_en = 'Deterrence framing (Western/NATO/Nordic mainstream) holds that Russian rearmament in the High North and growing Sino-Russian Arctic cooperation require NATO reinforcement -- exercises, bases, icebreakers and readiness -- to defend allied territory and close a capability gap.', updated_at = NOW() WHERE id = 'arctic_nato_deterrence';
UPDATE narratives_v2 SET claim_en = 'Militarisation framing (Russian + Chinese state press) reverses the causality: NATO expansion, exercises and basing are the destabilising provocation that turns a zone of low tension into an arena of bloc confrontation and an arms race, encircling Russia.', updated_at = NOW() WHERE id = 'arctic_nato_militarization';
UPDATE narratives_v2 SET claim_en = 'Development framing (Russian state + Western energy/business press) treats Arctic hydrocarbons and critical minerals as a legitimate, economically vital resource to be developed -- new discoveries, investment, production and jobs -- as retreating ice opens access.', updated_at = NOW() WHERE id = 'arctic_resource_development';
UPDATE narratives_v2 SET claim_en = 'Opportunity framing (Russian + Chinese + commercial press) presents the Northern Sea Route, Northwest Passage and Polar Silk Road as shorter, developable trade corridors and a legitimate economic prospect, with icebreaker fleets and Arctic ports as investment.', updated_at = NOW() WHERE id = 'arctic_route_opportunity';
UPDATE narratives_v2 SET claim_en = 'Strategic-threat framing (Western security press) treats Russian dominance of the Northern Sea Route and China''s Polar Silk Road ambitions as a chokepoint risk requiring monitoring, freedom-of-navigation assertion and sanctions -- including the "shadow fleet" and dual-use shipping.', updated_at = NOW() WHERE id = 'arctic_route_strategic_threat';
UPDATE narratives_v2 SET claim_en = 'Russian and Chinese counter-framing (Russian state press and Chinese state media) reverses the Western account: NATO''s northern expansion is the destabilizing militarization of a once-low-tension zone and an encirclement of Russia, and the US push on Greenland is imperialist overreach that exposes Western hypocrisy -- not a threat Moscow or Beijing pose but a pretext. It is adversarial to the Western Arctic posture as a whole.', updated_at = NOW() WHERE id = 'arctic_russia_china_counter';
UPDATE narratives_v2 SET claim_en = 'Western security-consensus framing (NATO, Nordic and US mainstream plus Western business press) holds that the Arctic is becoming a zone of strategic vulnerability that must be secured: Russian rearmament in the High North and deepening Sino-Russian cooperation require NATO deterrence, resource and shipping-route access must be protected, and allied sovereignty defended.', updated_at = NOW() WHERE id = 'arctic_western_security_consensus';
UPDATE narratives_v2 SET claim_en = 'Western sovereignty-and-stewardship framing (European and Western mainstream plus green press) resists the Arctic being carved up by coercion or reckless exploitation: it defends Danish and allied sovereignty and international law against the US Greenland push, is wary of Russian control of the sea routes, and treats the warming Arctic as a fragile climate system that drilling, mining and militarization endanger. Distinct from the security-consensus card, it is critical rather than martial.', updated_at = NOW() WHERE id = 'arctic_western_sovereignty_stewardship';
UPDATE narratives_v2 SET claim_en = 'Chinese and Russian state framing treats the pact as a Cold War bloc project: an Anglosphere grouping that transfers naval nuclear propulsion to a non-nuclear-weapon state, strains the non-proliferation regime, and drives regional militarisation under the banner of deterrence. US basing steps in Western Australia are reported as evidence of the build-up rather than as reassurance.', updated_at = NOW() WHERE id = 'aukus_bloc_confrontation';
UPDATE narratives_v2 SET claim_en = 'The critical Australian framing — carried by the same mainstream outlets — holds that the pact has been downgraded and politically strained: Australia will receive three second-hand submarines instead of new Virginia-class boats, a capability gap opens as the Collins-class fleet is downsized and enters a "high-risk" life extension, an inquiry has been warned of nuclear-disaster risk, an ex-minister crowd-funded his own inquiry, a former foreign minister called it among Australia''s worst foreign-policy decisions, and Labor is publicly split.', updated_at = NOW() WHERE id = 'aukus_capability_doubt';
UPDATE narratives_v2 SET claim_en = 'The supportive Australian framing holds that the submarine pact remains the cornerstone of Australian deterrence and is delivering: a $2.7bn pledge to accelerate the shipyard, the US Navy standing up Naval Support Activity Stirling in Western Australia, AUKUS partners advancing SSN and underwater-drone programmes, savings identified in the revised arrangement, and senior figures publicly backing the plan.', updated_at = NOW() WHERE id = 'aukus_strategic_necessity';
UPDATE narratives_v2 SET claim_en = 'A distinct critical reading inside the Australian and Western press questions not China policy but the alliance itself: AUKUS has been revised down to three second-hand US submarines, a capability gap opens as the Collins-class fleet is downsized, a UK inquiry found the investment had "already faltered", and senior Australian figures — including a former foreign minister — describe the pact as among the country''s worst foreign-policy decisions. The concern is reliability and cost rather than the existence of a China problem.', updated_at = NOW() WHERE id = 'australia_alliance_scepticism';
UPDATE narratives_v2 SET claim_en = 'Chinese state media — with Russian outlets on AUKUS — reject the premise across every axis: the trade relationship is complementary and growing, and quota-triggered tariffs are routine administration rather than pressure; the espionage and military-threat assessments are hype, a "crafted rhetorical trap" and a grave strategic miscalculation; Pacific cooperation is requested by sovereign governments and should not be constrained by any third party; and AUKUS is Cold War bloc-building that spreads naval nuclear technology.', updated_at = NOW() WHERE id = 'australia_china_counter';
UPDATE narratives_v2 SET claim_en = 'The Australian and Western mainstream reading treats Australia''s position as one requiring active management: Chinese commercial leverage over iron ore, beef and critical minerals is a vulnerability to be diversified away from; espionage and interference findings and China''s growing strike reach justify the assessments its agencies make; and the answer across the Pacific is more partnership — defence treaties with Fiji and Vanuatu, alongside AUKUS.', updated_at = NOW() WHERE id = 'australia_western_consensus';
UPDATE narratives_v2 SET claim_en = 'Western mainstream framing treats the US retreat as the catalyst for a historic European awakening: the continent must build genuine strategic autonomy -- a defence union, industrial base, even a European deterrent -- through initiatives like ReArm Europe, to decide and defend for itself and de-risk from dependence on Washington. Broadly sympathetic to the project while debating its feasibility.', updated_at = NOW() WHERE id = 'autonomy_european_awakening';
UPDATE narratives_v2 SET claim_en = 'Skeptical framing (US conservative and Atlanticist-hawk press) mocks "strategic autonomy" and the "EU army" as a bureaucratic fantasy: Europe cannot defend itself, duplicates NATO, and should simply spend more inside the alliance rather than build rival structures that divide the West.', updated_at = NOW() WHERE id = 'autonomy_illusion';
UPDATE narratives_v2 SET claim_en = 'Rift-exploitation framing (Russian and Chinese state media) welcomes European "strategic autonomy" not out of solidarity but as the fracturing of the US-led bloc: proof that American hegemony is ending, that Europe should break free of its Atlantic vassalage, and that a multipolar order is arriving. It cheers the transatlantic split while doubting Europe will dare follow through.', updated_at = NOW() WHERE id = 'autonomy_multipolar_welcome';
UPDATE narratives_v2 SET claim_en = 'Rift-exploitation framing (Russian state press) presents the budget disputes as proof that the EU is broke, overstretched by rearmament and Ukraine, and fracturing between paymasters and dependants, amplifying the division rather than taking a side.', updated_at = NOW() WHERE id = 'budget_eu_decline_kremlin';
UPDATE narratives_v2 SET claim_en = 'Integration framing (the Commission and pro-integration mainstream) holds that new own resources and a larger budget are needed for competitiveness, defence and shared priorities, that rule-of-law conditionality is legitimate, and that reform of cohesion and agricultural spending should serve common European goals.', updated_at = NOW() WHERE id = 'budget_more_europe';
UPDATE narratives_v2 SET claim_en = 'Sovereignty framing (net-contributor governments, centre-right and sovereigntist voices, farm and business lobbies) holds that the proposed budget is unaffordable, that new EU taxes and own resources are a power grab into national competences and taxpayers'' money, and that Green Deal and agricultural rules are overreach to be resisted.', updated_at = NOW() WHERE id = 'budget_national_sovereignty';
UPDATE narratives_v2 SET claim_en = 'Chinese state framing rejects the assessments as manufactured: the Five Eyes espionage warning is called a "crafted rhetorical trap" and "highly ironic" given the alliance''s own surveillance record, and Australian think-tank claims of a Chinese military threat are called a grave strategic miscalculation. The argument is that the threat narrative is hype that serves alignment politics and damages a functioning relationship.', updated_at = NOW() WHERE id = 'china_threat_fabricated';
UPDATE narratives_v2 SET claim_en = 'Australian and allied coverage treats the threat assessment as evidence-based: ASIO sparring with Beijing over foreign interference, prosecutions of Chinese nationals for interference in Canberra, a jury finding an Australian expat acted as a Chinese spy asset, Five Eyes warnings that Chinese services recruit through fake job ads on professional networks, and Lowy Institute analysis that China''s capacity to strike targets in Australia is "real and growing" — underlined by a nuclear-capable ballistic missile test into the South Pacific.', updated_at = NOW() WHERE id = 'china_threat_substantiated';
UPDATE narratives_v2 SET claim_en = 'Coercion framing (Japanese and Western press) reads China''s rare-earth and dual-use export controls, entity blacklists, travel advisories, the collapse in Chinese tourism and the detention of Japanese nationals as a coordinated economic punishment for a political statement -- a repeat of the 2010 rare-earth showdown -- and treats supply concentration in Chinese hands as a strategic vulnerability. The response it presents is diversification: seabed mining, recycling, and joint stockpiling with Canada, France and G7 partners to find non-Chinese sources.', updated_at = NOW() WHERE id = 'cjer_economic_coercion';
UPDATE narratives_v2 SET claim_en = 'Lawful-regulation framing (Chinese state media) presents the export controls as ordinary licensing of dual-use items to military end-users, applied in accordance with Chinese law and international non-proliferation obligations and aimed at curbing Japan''s military build-up rather than at trade. It attributes the fall in tourism and business confidence to Japanese conduct -- an erosion of mutual trust caused by the prime minister''s remarks -- and casts detentions as ordinary law enforcement against violations of Chinese law, while presenting Japanese firms and G7 partners as unconvinced by Tokyo''s hardline stance.', updated_at = NOW() WHERE id = 'cjer_lawful_regulation';
UPDATE narratives_v2 SET claim_en = 'Western mainstream and Israeli framing: US, UK, French, and Italian forces in Syria and Iraq remain necessary to contain ISIS residue. SDF custody of ~10,000 ISIS detainees at al-Hol, al-Roj, and Hasaka prisons carries severe prison-break risk; the transitional government lacks capacity to take over; sustained coalition presence is the prudent option. Prescription: maintain coalition presence, continue strikes, condition detainee transfers on receiving-country capacity.', updated_at = NOW() WHERE id = 'coalition_counter_isis_necessary';
UPDATE narratives_v2 SET claim_en = 'Pro-Damascus and Turkish state framing: the new Syrian government must restore central authority over the northeast; the SDF is a separatist project backed by external powers (US, occasionally framed as Israeli/PKK collusion); Kurdish federalism would Balkanise Syria. Prescription: SDF disarmament and absorption into national army, no federal carve-out, end of US partnership with SDF.', updated_at = NOW() WHERE id = 'damascus_territorial_reunification';
UPDATE narratives_v2 SET claim_en = 'America-First framing (US conservative press) holds that European allies have underspent on defence for decades while sheltering under the US umbrella, and that Washington is right to demand they hit higher NATO spending targets or forfeit American protection. Troop drawdowns and blunt pressure are framed as overdue accountability.', updated_at = NOW() WHERE id = 'defence_europe_must_pay';
UPDATE narratives_v2 SET claim_en = 'Rift-exploitation framing (Russian and Chinese state media) casts the burden-sharing rows as proof that NATO is an obsolete Cold-War racket: Washington extracts money and arms sales from dependent Europeans while the alliance''s internal quarrels reveal its decay. Adversarial to the alliance as a whole, amplified with schadenfreude, not support for either party.', updated_at = NOW() WHERE id = 'defence_nato_racket';
UPDATE narratives_v2 SET claim_en = 'Western mainstream framing treats the fraying US security guarantee -- troop drawdowns, doubts over Article 5, transactional pressure -- as a strategic shock that leaves Europe dangerously exposed. Allies scramble to reassure Washington and raise spending to keep it engaged, while asking whether America will still come to their defence.', updated_at = NOW() WHERE id = 'defence_unreliable_america';
UPDATE narratives_v2 SET claim_en = 'Pro-cohesion framing (Western mainstream and pro-integration press) treats the Union''s shared rules as worth defending: rule-of-law conditionality and anti-corruption standards, a democratic order guarded against the radical right, solidarity on migration and budget, and a firewall against normalising forces hostile to the European project. It reads the disputes as tests the Union must pass to hold together.', updated_at = NOW() WHERE id = 'eu_cohesion_hold';
UPDATE narratives_v2 SET claim_en = 'Counter-framing (Russian and Chinese state media) reads every internal European dispute as evidence that Brussels coerces its members and that a Europe of sovereign nations dealing bilaterally would serve them better. Moscow and Beijing prefer direct relations with national capitals over the EU''s supranational authority, so they amplify the sovereigntist case and every sign of division — adversarial to Brussels and to European cohesion as a whole, not a genuine party in the internal disputes they magnify.', updated_at = NOW() WHERE id = 'eu_fracture_rift_exploitation';
UPDATE narratives_v2 SET claim_en = 'America-First framing (US conservative press) runs across the whole theater: Europe has exploited US trade openness, freeloaded on US defence, and harasses American tech champions -- so tariffs, blunt burden-sharing pressure and retaliation over EU tech rules are justified tools to force fair terms and put America first. Europe is a partner to be disciplined, not indulged.', updated_at = NOW() WHERE id = 'europe_us_america_first';
UPDATE narratives_v2 SET claim_en = 'Western and European mainstream framing treats the Trump-era pressure -- tariffs, burden-sharing threats, wavering security guarantees, tech confrontation -- as the rupture of a decades-old partnership that leaves Europe exposed and coerced. The response it champions is unity, countermeasures, strategic autonomy and digital sovereignty: an alarmed continent forced to decide and defend for itself.', updated_at = NOW() WHERE id = 'europe_us_transatlantic_rupture';
UPDATE narratives_v2 SET claim_en = 'Rift-exploitation framing (Russian and Chinese state media) reads every transatlantic quarrel -- tariffs, burden rows, the "EU army", tech fights -- not as taking sides but as proof that the US treats Europe as milkable vassals, that Western unity and values are hypocrisy, and that American hegemony is giving way to a multipolar order. Adversarial to the West as a bloc, amplified with schadenfreude.', updated_at = NOW() WHERE id = 'europe_us_western_disunity';
UPDATE narratives_v2 SET claim_en = 'Sovereigntist framing (national-conservative governments and sympathetic voices across member states) holds that Brussels overreaches into national competences, budgets and identity, that mainstream parties wrongly exclude movements millions vote for, and that member states should reclaim control over migration, money and the rule of their own institutions. It runs from within the Union, not against its existence.', updated_at = NOW() WHERE id = 'eu_sovereigntist_revolt';
UPDATE narratives_v2 SET claim_en = 'Russian, Iranian, Turkish, and post-Assad Syrian framing: Western military presence in Syria violates Syrian sovereignty; counter-ISIS operations should transfer to the new Syrian government and Iraqi authorities; ISIS detainees should be transferred to national jurisdictions; the coalition mandate has outlived its purpose. Prescription: full coalition withdrawal, transfer of detainees, end of US-SDF partnership, Syrian forces assume counter-terrorism responsibility.', updated_at = NOW() WHERE id = 'foreign_military_withdrawal_demand';
UPDATE narratives_v2 SET claim_en = 'Counter-framing (Russian state press) presents French turmoil, government collapses and unrest as proof of a failing Western model and elite disconnect. Moscow prefers dealing with sovereign national leaderships over Brussels-aligned elites, so it amplifies the instability and the anti-establishment case rather than endorsing any French party.', updated_at = NOW() WHERE id = 'france_decline_kremlin';
UPDATE narratives_v2 SET claim_en = 'Popular-will framing (voiced by the party and sympathetic commentary) holds that the judicial cases against Marine Le Pen and the marginalisation of the movement are an establishment and judicial effort to deny voters the leader they prefer ahead of 2027.', updated_at = NOW() WHERE id = 'france_popular_will';
UPDATE narratives_v2 SET claim_en = 'Republican-defense framing (French and Western mainstream) treats the Rassemblement National as a challenge to republican norms and the embezzlement case and any resulting ineligibility as the ordinary application of the law, and views the governing instability as the price of the party''s rise.', updated_at = NOW() WHERE id = 'france_republican_defense';
UPDATE narratives_v2 SET claim_en = 'Western shipping-desk, Israeli, and Saudi framing: Houthi attacks on commercial vessels violate UNCLOS freedom-of-navigation rights and global trade order; Operation Prosperity Guardian, EU Aspides, and US Fifth Fleet operations are necessary and lawful; Saudi Yanbu rerouting and reported Somaliland base are pragmatic adaptations. Prescription: maintain coalition naval presence, escort merchant traffic, sanction Houthi enablers.', updated_at = NOW() WHERE id = 'freedom_of_navigation_defense';
UPDATE narratives_v2 SET claim_en = 'Frontline-freeze framing (Trump-aligned American press + Hungarian/Slovak-aligned EU + Turkish + Indian + Chinese + Brazilian + broader Global South) holds that the war is unwinnable for either side at acceptable cost and that a pragmatic settlement requires freezing the line of contact, formalising Ukrainian neutrality (no NATO accession), building a multilateral security guarantee structure outside NATO, lifting sanctions in phases tied to verified compliance, and allowing refugee return. Crucially, this position does NOT endorse Russian maximalist objectives — no demilitarisation of the Ukrainian Armed Forces, no denazification framework, no formal international recognition of annexed territories (de facto control accepted, de jure recognition deferred). The framework is closer to a Korean armistice than to a Russian victory. The Anchorage track (sometimes "spirit of Anchorage") refers to Trump-Putin diplomatic efforts to crystallise this position. Prescription: immediate freeze; Istanbul-style talks; Ukrainian constitutional neutrality with security backstops outside NATO; phased sanctions relief tied to compliance.', updated_at = NOW() WHERE id = 'frontline_freeze_settlement';
UPDATE narratives_v2 SET claim_en = 'Self-determination framing (Greenlandic/Nordic voices) centres Greenland''s own agency: the island is not for sale, its people decide their future, and the crisis accelerates the independence debate vis-à-vis both Denmark and the United States. Distinct from EU sovereignty-defense, which speaks for Denmark/Brussels.', updated_at = NOW() WHERE id = 'greenland_self_determination';
UPDATE narratives_v2 SET claim_en = 'Sovereignty-defense framing (Western mainstream) treats US pressure on Greenland as an unacceptable coercion of an ally, a violation of territorial integrity and international law, and a test of European unity -- met with condemnation, protests, counter-tariffs and troop deployments. It defends Denmark''s and the EU''s position against Washington.', updated_at = NOW() WHERE id = 'greenland_sovereignty_defense';
UPDATE narratives_v2 SET claim_en = 'US-manifest-destiny framing (Trump-aligned American press) holds that acquiring or controlling Greenland is a core national-security interest -- for Arctic bases, rare-earth minerals and sea lanes -- justified by Russian and Chinese encroachment, and that Washington should secure it "one way or the other". Genuine advocacy is thin relative to overall coverage.', updated_at = NOW() WHERE id = 'greenland_us_strategic_claim';
UPDATE narratives_v2 SET claim_en = 'Rift-exploitation framing (Russian state press + Chinese state media) frames the episode not as support for a US takeover but as proof of Western hypocrisy and imperialism: Washington behaves as a 21st-century coloniser toward an ally, the "Russian/Chinese threat" to Greenland is a manufactured pretext (which even Western officials deny), and the transatlantic rift it opens is amplified with schadenfreude. It is adversarial to the US and to Western cohesion, NOT an endorsement of annexation.', updated_at = NOW() WHERE id = 'greenland_western_hypocrisy';
UPDATE narratives_v2 SET claim_en = 'Resistance-axis and critical pan-Arab framing: the de facto Sanaa authority represents Yemeni national resistance to Saudi and Western intervention; the Saudi-led coalition is an aggressor that has destroyed Yemeni infrastructure; the STC was a UAE-backed colonial project whose collapse exposes coalition failure. Prescription: international acceptance of de facto Sanaa governance, end of coalition strikes, withdrawal of foreign forces.', updated_at = NOW() WHERE id = 'houthi_authority_legitimate_resistance';
UPDATE narratives_v2 SET claim_en = 'Israeli, pro-Israel, and Saudi-aligned framing: Houthi strikes are Iranian-orchestrated proxy aggression demanding kinetic response on Yemeni soil (Hodeidah port, Sanaa airport, Houthi leadership) plus expanded regional partnerships (Somaliland base, deeper Gulf cooperation) to interdict Iranian weapons pipelines. Prescription: continue Israeli strikes on Yemeni targets, build Somaliland-Eilat air-defense partnership, sanction Iranian transit nodes.', updated_at = NOW() WHERE id = 'houthi_iranian_proxy_aggression';
UPDATE narratives_v2 SET claim_en = 'Resistance-axis framing: Houthi targeting of Israel-linked shipping is a legitimate non-state form of pressure tied explicitly to a Gaza ceasefire; Western naval coalitions and reported Israeli outposts in Somaliland are imperial overreach into Yemeni and Arab maritime sovereignty. Prescription: continue selective targeting until Gaza ceasefire; reject Western coalitions as illegitimate; oppose foreign basing on the Horn.', updated_at = NOW() WHERE id = 'houthi_naval_pressure_legitimate';
UPDATE narratives_v2 SET claim_en = 'Resistance-axis framing: Houthi missile and drone attacks on Israel are legitimate solidarity action with Gaza, coordinated with Iran and Hezbollah under a single axis-of-resistance command, deepening Israeli vulnerability and establishing a new deterrence equation. Prescription: integrated axis operations until Gaza ceasefire; develop Houthi missile and drone capabilities further.', updated_at = NOW() WHERE id = 'houthi_resistance_strikes_legitimate';
UPDATE narratives_v2 SET claim_en = 'Resistance / Iran-aligned framing: Houthi attacks on Israel and Red Sea shipping are legitimate solidarity-with-Gaza pressure under a unified axis-of-resistance command; the Yemeni movement has the right to extend the war until Gaza ceasefire holds. Prescription: maintain pressure until Gaza ceasefire; integrate Houthi operations into unified resistance posture.', updated_at = NOW() WHERE id = 'houthis_fourth_front_solidarity';
UPDATE narratives_v2 SET claim_en = 'Counter-framing (Russian state press, and the sovereignty case generally) holds that the conditionality fight and the funds freeze were Brussels overreaching against a democratically elected government and infringing national sovereignty. Moscow favours direct dealings with national capitals over Brussels'' supranational authority, so it amplifies the sovereigntist critique and every sign of EU heavy-handedness — aligned against Brussels rather than endorsing a specific Hungarian faction.', updated_at = NOW() WHERE id = 'hungary_brussels_coercion';
UPDATE narratives_v2 SET claim_en = 'Standards-defense framing (Western mainstream) holds that judicial independence, media freedom, anti-corruption and the conditionality mechanism are non-negotiable European commitments, that the frozen funds were a justified response to backsliding, and that the post-transition clean-up of captured institutions is democratic renewal.', updated_at = NOW() WHERE id = 'hungary_eu_standards';
UPDATE narratives_v2 SET claim_en = 'Sovereignty framing (national-conservative sympathisers and the ousted camp''s own voice) holds that the conditionality fight was Brussels punishing a democratically elected government and infringing national sovereignty, and reads the domestic reckoning that followed the change of government as political revenge against opponents.', updated_at = NOW() WHERE id = 'hungary_sovereignty_interference';
UPDATE narratives_v2 SET claim_en = 'Arab capitals (Saudi, Gulf, Egypt) moved first with investment and recognition trajectories; Western capitals followed with calibrated sanctions easing and high-level visits; Russia negotiates base continuity; Ukraine made a symbolic security-talks visit. The shared logic: realism over purity tests, pull Syria out of the Iranian orbit, fund reconstruction, stabilise the Levant. Prescription: continue calibrated engagement, condition relief on reform milestones, fund reconstruction, maintain dialogue.', updated_at = NOW() WHERE id = 'international_engagement_pragmatic';
UPDATE narratives_v2 SET claim_en = 'Saudi / Egyptian state, Israeli, and pro-Western framing: Houthis are an Iranian-armed proxy that has hijacked the Yemeni state, threatens Arab order, and must be militarily defeated; STC fracture is one symptom of the broader Iran-axis destabilisation. Prescription: military defeat of Houthi capability, restoration of legitimate Yemeni government, interdiction of Iranian weapons pipelines.', updated_at = NOW() WHERE id = 'iran_proxy_destabilisation';
UPDATE narratives_v2 SET claim_en = 'Israeli sources frame strikes inside Syria as legitimate preventive defense: residual Hezbollah logistics and Iranian assets in southern Syria remain a threat; the new transitional government inherits the security obligation; Golan-adjacent buffer-zone enforcement is a non-negotiable Israeli security perimeter. Prescription: continue strikes until threat capability is degraded, maintain buffer zone, condition relations with Damascus on Israeli security demands.', updated_at = NOW() WHERE id = 'israeli_strikes_on_syria_legitimate';
UPDATE narratives_v2 SET claim_en = 'Interference framing (Chinese state media) holds that Taiwan is an internal Chinese affair on which Japan has no standing to comment, that the prime minister''s remarks were erroneous and unlawful, crossed a red line and violated the one-China principle and the four political documents that underpin postwar China-Japan relations, and that they -- not any Chinese response -- are the root cause of the current state of ties. Japan is called on to reflect, correct and retract, and its invocation of collective self-defence is cast as a pretext for intervention and bloc confrontation given its wartime record.', updated_at = NOW() WHERE id = 'jc_taiwan_interference_charge';
UPDATE narratives_v2 SET claim_en = 'Security-stake framing (Japanese and Western press) holds that Taiwan''s proximity to Japan''s southwestern islands makes a Taiwan contingency a direct question of Japanese national survival, that a prime minister may say so openly, and that Beijing''s response -- demands for retraction, blacklists, mineral restrictions and pressure on tourism -- is coercion aimed at silencing legitimate security debate in a democracy. It reads Japan''s destroyer transits of the Taiwan Strait and its deepening ties with Washington, Manila and G7 partners as lawful and defensive.', updated_at = NOW() WHERE id = 'jc_taiwan_japan_security_stake';
UPDATE narratives_v2 SET claim_en = 'Deterrence framing (Japanese and Western press) presents Japan''s counter-strike capability, higher defense spending, eased equipment-transfer rules and closer alignment with the United States, NATO and regional partners as a proportionate and exclusively defence-oriented answer to a deteriorating security environment -- Chinese naval and air activity around the southwestern islands, missile growth, and the Taiwan contingency. It records Tokyo''s rejection of the militarism charge and names China as the principal concern in its own doctrine documents.', updated_at = NOW() WHERE id = 'jde_deterrence_response';
UPDATE narratives_v2 SET claim_en = 'Militarism-revival framing (Chinese state media, echoed by Russian outlets) holds that Japan''s counter-strike missiles, rising defense budget, scrapped arms-export limits, renamed ranks and constitutional-revision push together hollow out the pacifist constitution and dismantle the postwar order imposed after 1945, revealing a state reverting to its militarist past behind a "peaceful nation" disguise. The China threat is cast as fearmongering manufactured to justify the build-up, and the international community is urged to stay vigilant and coordinate export controls in response.', updated_at = NOW() WHERE id = 'jde_militarism_revival';
UPDATE narratives_v2 SET claim_en = 'Western liberal, pan-Arab Al Jazeera, and Israeli centrist framing: Turkey''s anti-PKK framing collapses legitimate Kurdish political representation (DEM Party, HDP heritage) into terror designation; YPG / SDF in Syria are democratic partners against ISIS, not PKK affiliates; Ocalan''s Imrali messaging shows willingness for political resolution that Ankara repeatedly rejects; cross-border strikes risk regional escalation. Prescription: separate political Kurdish representation from PKK terror designation; support DEM Party participation; protect SDF in Syria.', updated_at = NOW() WHERE id = 'kurdish_political_rights_critique';
UPDATE narratives_v2 SET claim_en = 'Western mainstream, Israeli, and parts of Arab coverage frame the SDF-led Autonomous Administration of North and East Syria (AANES) as a multi-ethnic democratic experiment that fought ISIS, jails 10,000+ detainees on behalf of the international community, and deserves protection from Turkish and Damascus pressure. Prescription: maintain US partnership, prevent Turkish operations, condition Damascus normalisation on Kurdish rights, support federal arrangement.', updated_at = NOW() WHERE id = 'kurdish_self_administration';
UPDATE narratives_v2 SET claim_en = 'Accountability framing (Chinese state media, echoed by Russian outlets) holds that Japan has never genuinely reckoned with its war of aggression: offerings to Yasukuni honour convicted war criminals, denial of the Nanjing Massacre and of the coercion of "comfort women" persists among right-wing figures, wartime rank titles are being restored, abandoned chemical weapons remain undestroyed, and looted cultural relics remain unreturned. Newly opened archives and scholar campaigns are presented as undeniable evidence, and the historical record is explicitly linked to a present-day militarist drift that the victimized countries are urged not to forget.', updated_at = NOW() WHERE id = 'memory_historical_accountability';
UPDATE narratives_v2 SET claim_en = 'Leverage framing (Japanese and Western press) reports historical disputes primarily as a barometer of the wider political relationship: a ritual offering to Yasukuni or a rank-renaming is noted for the reaction it will provoke in Beijing rather than adjudicated, prime-ministerial observances are described as made in a private capacity, and the timing of archive openings, relic-restitution campaigns and anniversary commemorations is read against the state of bilateral ties. It neither endorses nor rebuts the historical charges, and records Tokyo''s rejection of the militarism framing attached to them.', updated_at = NOW() WHERE id = 'memory_political_leverage';
UPDATE narratives_v2 SET claim_en = 'Counter-framing (Russian state press) presents EU migration as chaos, division and the failure of a hypocritical Europe — often measured against Russia''s own large migrant and refugee inflows and integration strains — amplifying the disputes between member states as evidence of decline rather than taking a side on asylum policy.', updated_at = NOW() WHERE id = 'migration_eu_failure_kremlin';
UPDATE narratives_v2 SET claim_en = 'Control framing (national governments and centre-right and sovereigntist voices) holds that irregular migration must be curbed through tougher borders, faster returns, offshore processing and restriction, that generous regularisation sets the wrong incentives, and that member states, not Brussels, should decide.', updated_at = NOW() WHERE id = 'migration_national_control';
UPDATE narratives_v2 SET claim_en = 'Solidarity-and-rights framing (Western mainstream and pro-integration voices) holds that asylum is a legal obligation, that the Pact''s burden-sharing must be honoured, that detention and pushbacks that courts find unlawful are unacceptable, and that regularisation and integration are legitimate answers.', updated_at = NOW() WHERE id = 'migration_solidarity_rights';
UPDATE narratives_v2 SET claim_en = 'Pro-Turkey and NATO-aligned framing: Iran''s ballistic missile crossing Turkish airspace was an act of aggression intercepted by NATO; the Patriot redeployment to Malatya from Ramstein is legitimate alliance solidarity; Erdogan''s call for de-escalation is responsible great-power behaviour, not appeasement. Prescription: maintain NATO commitment to Turkish territorial defence; treat Iranian airspace violations as alliance-level provocations.', updated_at = NOW() WHERE id = 'nato_solidarity_territorial_defense';
UPDATE narratives_v2 SET claim_en = 'Chinese state framing presents Beijing''s Pacific presence as normal, mutually agreed cooperation — medical teams, infrastructure and policing assistance requested by sovereign governments — that "should not target any third party or be used for geopolitical contest". Australian and Western reporting on Chinese pacts is cast as hype driven by an exclusionary Cold War mindset that denies island states their own choices.', updated_at = NOW() WHERE id = 'pacific_china_cooperation';
UPDATE narratives_v2 SET claim_en = 'Australian and Western coverage frames the Pacific as a region where Australia is consolidating its position as security partner of choice: the Fiji mutual defence treaty, the Vanuatu pact barring foreign military bases, and the Solomon Islands review of its secret pact with Beijing are read as island states freely choosing transparent partnerships over Chinese basing and policing arrangements.', updated_at = NOW() WHERE id = 'pacific_western_partnership';
UPDATE narratives_v2 SET claim_en = 'Turkish state desk framing: the PKK and its Syrian YPG / SDF affiliates are a unified terrorist organisation; the only acceptable political process is full disarmament and dissolution; cross-border operations against YPG positions in Syria and PKK leadership in Iraq are legitimate counter-terrorism; "terror-free Türkiye" is the binding state doctrine. Bahceli''s 2024 opening and Ocalan''s Imrali messaging are accepted only on these terms. Prescription: continue cross-border operations until PKK is dissolved; condition any political accommodation on disarmament.', updated_at = NOW() WHERE id = 'pkk_terror_full_disarmament';
UPDATE narratives_v2 SET claim_en = 'Counter-framing (Russian and Chinese state media) presents the realignment as the collapse of a discredited European liberal centre and the vindication of forces opposed to Brussels and to Ukraine support. Moscow and Beijing favour a Europe of sovereign nations dealing bilaterally over Brussels'' supranational authority, so they amplify the shift as Western decline rather than endorsing a specific party.', updated_at = NOW() WHERE id = 'realignment_center_decline_kremlin';
UPDATE narratives_v2 SET claim_en = 'Firewall-defense framing (centre-left, greens and pro-cordon voices) holds that mainstream parties, above all the EPP, must not legitimise or govern with national-conservative and radical-right forces, that the cordon sanitaire protects liberal democracy, and that its erosion is dangerous.', updated_at = NOW() WHERE id = 'realignment_firewall_defense';
UPDATE narratives_v2 SET claim_en = 'Realignment framing (centre-right and national-conservative voices) holds that parties representing a large share of voters have a democratic mandate, that cooperation across the old cordon is legitimate and overdue, and that a new centre-right-to-national-conservative majority is a normal democratic outcome.', updated_at = NOW() WHERE id = 'realignment_new_majority';
UPDATE narratives_v2 SET claim_en = 'Israeli right, Iranian state media, and Western conservative voices frame each act of engagement — Saudi investment deals, sanctions relief, head-of-state meetings with al-Sharaa, Russian base preservation, Ukrainian Damascus visit — as whitewashing a former al-Qaeda operative and rewarding extremism. The image of world leaders shaking the hand of a designated terrorist is itself the harm. Prescription: maintain terrorist designation, halt sanctions relief, refuse high-level engagement, sanction enablers.', updated_at = NOW() WHERE id = 'recognition_legitimises_jihadists';
UPDATE narratives_v2 SET claim_en = 'Reform-progress framing (Ukrainian reformist press + Western mainstream + EU policy outlets) treats ongoing corruption investigations as evidence that Ukrainian anti-corruption infrastructure built since 2014 is functioning under wartime stress. Coverage tracks NABU, SAP, HACC, and NACP investigations of senior officials including Presidential Office personnel, defense procurement scandals, and regional governors. Coverage frames Western audit demands as legitimate and constructive, presents prosecutions of senior officials as proof of independence from the Presidential Office, and contextualises scandals within the broader institutional transformation since 2014. Prescription: sustain institutional protection from political interference; maintain Western conditionality leverage; complete judicial reform; continue prosecuting irrespective of rank.', updated_at = NOW() WHERE id = 'reform_in_progress';
UPDATE narratives_v2 SET claim_en = 'Russian and Iranian state media frame the fall of Assad and the rise of a Turkey- and West-aligned transitional government as a setback for the multipolar order. Prescription: preserve Russian basing through negotiation, maintain residual Iranian channels, frame transition as illegitimate Western-Turkish project.', updated_at = NOW() WHERE id = 'russia_iran_loss_lament';
UPDATE narratives_v2 SET claim_en = 'Russian maximalist framing (Russian state press + Belarusian state) holds that any settlement must address the root causes of the war by achieving all stated objectives of the special military operation. The framework: complete denazification of Ukrainian leadership and institutions, demilitarisation of the Ukrainian Armed Forces to defined caps, formal constitutional neutrality (no NATO accession ever, no foreign bases), formal international recognition of all four annexed regions (Donetsk, Luhansk, Zaporizhzhia, Kherson) plus Crimea within their claimed administrative boundaries, full restoration of Russian-language rights, complete lifting of all sanctions, return of all frozen sovereign assets, and a binding US/NATO commitment to no further eastern expansion. Prescription: any settlement that does not deliver these objectives is unacceptable; negotiations are useful only as a venue to achieve them; military operations continue until objectives are met or accepted at the negotiating table.', updated_at = NOW() WHERE id = 'russian_maximalist_peace';
UPDATE narratives_v2 SET claim_en = 'Sanctions-ineffective framing (Russian state press + Global South + Chinese state press + Hungarian-aligned EU) argues that the sanctions package has hurt European economies more severely than Russia, that the Russian economy has successfully adapted through parallel imports, currency controls, BRICS settlement, and Asian energy markets, and that frozen-asset seizure would set a precedent destroying global trust in the Western financial system. Coverage emphasises German industrial decline, French inflation, US shale-gas profiteering at European expense, growing Global South neutrality, and the historical failure of sanctions to change behaviour. Prescription: lift or phase out sanctions as part of any peace deal; halt frozen-asset seizure plans; restore Russian energy supply to Europe; recognise multipolar financial reality.', updated_at = NOW() WHERE id = 'sanctions_ineffective_and_backfiring';
UPDATE narratives_v2 SET claim_en = 'Saudi, Egyptian, and pan-Arab Sunni framing: the Saudi-led coalition is restoring the internationally-recognised Yemeni government; Houthi rule in Sanaa is an Iran-backed coup; STC self-dissolution and southern unification under the Presidential Leadership Council are necessary; UAE-backed separatism was a destabilising mistake. Prescription: continued coalition military pressure on Houthi forces, southern political consolidation under the PLC, Saudi-funded reconstruction.', updated_at = NOW() WHERE id = 'saudi_coalition_legitimacy_restoration';
UPDATE narratives_v2 SET claim_en = 'Sovereignty framing (Chinese state media) holds that China''s claims to the Nansha, Xisha, Zhongsha and Huangyan features rest on historic rights and are consistent with international law; that the 2016 arbitral award is invalid, non-binding and "waste paper"; and that coast guard activity is routine rights-protection law enforcement in Chinese waters. It locates the source of instability in the Philippines and in external powers -- chiefly the United States, and increasingly Japan -- whose operations, exercises and arms transfers are cast as militarising the sea and as interference by states that are not parties to the dispute.', updated_at = NOW() WHERE id = 'scs_chinese_sovereignty_claim';
UPDATE narratives_v2 SET claim_en = 'Rules-based framing (Western, Philippine, Japanese and Southeast Asian press) treats the 2016 arbitral award as binding and the nine-dash line as without legal basis under UNCLOS, and reads Chinese coast guard and maritime-militia conduct -- water cannon, blocking, shadowing, and structures placed on contested features -- as coercion of smaller claimants inside their exclusive economic zones. It presents allied naval presence, joint patrols, exercises such as Balikatan and an effective ASEAN code of conduct as the legitimate response, and treats incidents at Scarborough Shoal and Second Thomas Shoal as tests of the alliance.', updated_at = NOW() WHERE id = 'scs_rules_based_maritime_order';
UPDATE narratives_v2 SET claim_en = 'Rights-protection framing (Chinese state media) holds that Diaoyu Dao and its affiliated islets have been Chinese territory since ancient times, that China Coast Guard patrols in the surrounding waters are routine and lawful rights-protection law enforcement in Chinese jurisdiction, and that Japanese vessels entering those waters are the intruders being lawfully expelled. Japanese protests are cast as provocation, and the friction is tied to Tokyo''s accelerating remilitarisation rather than to Chinese activity.', updated_at = NOW() WHERE id = 'senkaku_chinese_rights_protection';
UPDATE narratives_v2 SET claim_en = 'Administration framing (Japanese and Western press) treats the Senkakus as territory under Japanese administrative control and reads China Coast Guard entries into the surrounding territorial waters and contiguous zone -- along with survey ships, buoys and drilling structures placed near the median line -- as sustained grey-zone pressure intended to normalise a Chinese presence and erode that control without triggering armed conflict. Incidents are counted and protested rather than escalated.', updated_at = NOW() WHERE id = 'senkaku_japanese_administration';
UPDATE narratives_v2 SET claim_en = 'UN, Western humanitarian, and pan-Arab non-aligned outlets frame the Sudan war as a humanitarian catastrophe with genocide-level violence concentrated in Darfur and El Fasher. Evidence: 12M displaced, induced famine via siege and aid blockade, systematic ethnic violence by RSF against Masalit and other African communities, hospital and aid-convoy strikes, UN investigative findings of genocide in El Fasher. Prescription: immediate ceasefire, unimpeded humanitarian access, accountability via ICC, neither side has a legitimate path to total victory.', updated_at = NOW() WHERE id = 'sudan_humanitarian_catastrophe';
UPDATE narratives_v2 SET claim_en = 'Investigative international and Turkish/Iranian state media frame the Sudan war as "the world''s worst proxy war": the RSF is sustained by UAE arms transferred via Chad and Ottilien Ethiopian routes; Russian Africa Corps / Wagner extracts gold from RSF-held territories; Egypt and Saudi backing of the army is the counter-axis. External powers, not Sudanese choice, drive the war''s length. Prescription: international sanctions on RSF backers, transparency on arms flows, condition Gulf relationships on Sudan stance.', updated_at = NOW() WHERE id = 'sudan_proxy_war_critique';
UPDATE narratives_v2 SET claim_en = 'Pan-Arab Egyptian, Saudi, and Turkish-state coverage frames the Sudanese army as the constitutional state defending against an armed mutiny by the RSF. Islamist / Brotherhood elements within the army are treated as a manageable internal matter relative to the existential RSF threat. Prescription: international support for the Sudanese government, sanctions on RSF backers, no negotiations that legitimise RSF as a co-equal party.', updated_at = NOW() WHERE id = 'sudan_state_legitimacy';
UPDATE narratives_v2 SET claim_en = 'Pro-Israel, Iranian state, and Western conservative voices frame HTS rule substantively: al-Sharaa is a former al-Qaeda operative, the transition is cosmetic, sectarian violence against Alawites, Druze, and Christians is already underway, governance is fragile and ideologically extremist. Evidence: incidents in coastal Alawite communities, restrictions on minorities, jihadist factions within the HTS coalition. Prescription: maintain terrorist designation, withhold recognition, sanction sectarian actors, protect minorities.', updated_at = NOW() WHERE id = 'syria_jihadist_takeover_warning';
UPDATE narratives_v2 SET claim_en = 'Pro-engagement coverage frames the HTS-led transitional government under al-Sharaa as a legitimate post-Assad outcome. Prescription: recognise the transition, lift sanctions, fund reconstruction, integrate Syria into regional architecture (Arab League, GCC).', updated_at = NOW() WHERE id = 'syria_legitimate_transition';
UPDATE narratives_v2 SET claim_en = 'Pan-Arab, Iranian, Turkish, and post-Assad Syrian state coverage frames Israeli strikes on Syrian territory as aggression that violates Syrian sovereignty and undermines the legitimate transition. The buffer zone south of Damascus is framed as illegal occupation. Prescription: end Israeli strikes, withdraw from buffer zone, condition any Syrian-Israeli engagement on Israeli compliance with international law.', updated_at = NOW() WHERE id = 'syrian_sovereignty_under_israeli_aggression';
UPDATE narratives_v2 SET claim_en = 'Rift-exploitation framing (Russian and Chinese state media) casts American technological dominance over Europe as digital colonialism and mass surveillance, presenting the EU-US tech clash as belated European recognition of its subjugation to Silicon Valley -- while stressing Washington''s hypocrisy on "free" markets. Adversarial to US tech hegemony, not an endorsement of EU regulation as such.', updated_at = NOW() WHERE id = 'tech_digital_colonialism';
UPDATE narratives_v2 SET claim_en = 'Western and European mainstream framing treats EU enforcement against US Big Tech -- DMA/DSA fines, antitrust probes, content and privacy rules -- as legitimate rule-of-law that Europe must uphold, and pairs it with a drive for digital sovereignty: sovereign cloud, Gaia-X and weaning public and defence systems off American providers.', updated_at = NOW() WHERE id = 'tech_digital_sovereignty';
UPDATE narratives_v2 SET claim_en = 'America-First framing (US conservative press) casts the DMA, DSA and antitrust fines as protectionist, anti-innovation harassment designed to shake down US technology champions and censor American speech, justifying tariff retaliation to defend them.', updated_at = NOW() WHERE id = 'tech_eu_overreach';
UPDATE narratives_v2 SET claim_en = 'Cambodian framing (reaching the corpus through international wire quotes, as no Cambodian outlets are present) holds that Thailand occupies Cambodian territory -- including ground it did not withdraw from after the ceasefire -- and that the 1962 and 2013 International Court of Justice rulings on Preah Vihear and the surrounding area, together with proper demarcation, establish Cambodia''s claim. It presents Cambodia as the aggrieved smaller party seeking demarcation, international adjudication and UNCLOS process rather than force.', updated_at = NOW() WHERE id = 'thaicam_cambodian_territorial_claim';
UPDATE narratives_v2 SET claim_en = 'Mediation framing (Chinese state media) presents the conflict primarily as an occasion for external de-escalation, foregrounding China''s own mediation and Track-II diplomacy, ASEAN''s role under the chair, and the maintenance of the ceasefire, rather than endorsing either side''s territorial claim. It reports incidents in neutral terms -- often attributing them to Thai or Cambodian sources -- and stresses the economic cost of continued conflict and the value of a negotiated settlement.', updated_at = NOW() WHERE id = 'thaicam_great_power_mediation';
UPDATE narratives_v2 SET claim_en = 'Thai framing (Thai press) treats the disputed frontier and the island of Koh Kood as inviolable Thai sovereign territory, and casts Cambodia as the party that repeatedly breaches the boundary memoranda (MOU 43/44), moves troops and tanks toward the line, and manufactures or exaggerates incidents. It presents the Royal Thai Army''s posture as defensive and lawful, frames Cambodia''s UNCLOS move over the maritime area as a unilateral provocation that Thailand need not answer, and treats calls to scrap MOU 43 as a response to Cambodian violations.', updated_at = NOW() WHERE id = 'thaicam_thai_sovereignty_defence';
UPDATE narratives_v2 SET claim_en = 'Tighten-and-seize framing (Ukrainian press + Western mainstream + Eastern European) treats sanctions as a necessary economic constraint on the Russian war machine and argues for both deepening the package and shifting from freeze to seizure. Coverage emphasises evidence of Russian economic stress (rouble pressure, defense industrial bottlenecks, labour shortages), the inadequacy of the current price cap as enforced, and the moral and practical case for converting frozen assets into reparations. Prescription: lower the oil price cap; aggressive secondary sanctions on third-country evaders; full seizure of frozen sovereign assets; expand SDN designations; close dual-use loopholes.', updated_at = NOW() WHERE id = 'tighten_and_seize';
UPDATE narratives_v2 SET claim_en = 'Australian and Western business coverage reads Beijing''s commercial levers as strategic risk: the 55% tariff triggering at the beef quota threshold, the state buyer restricting Fortescue and BHP iron ore cargoes during price talks, and Chinese stakes in rare-earth projects forced into divestment. The conclusion drawn is that market concentration must be reduced through diversification, investment screening and alternative supply chains.', updated_at = NOW() WHERE id = 'trade_derisking_necessity';
UPDATE narratives_v2 SET claim_en = 'Western mainstream framing treats US tariffs as damaging economic coercion against a vital ally, threatening a mutually destructive trade war, and argues Europe must respond with unity, credible counter-tariffs and a negotiated deal that protects its industries and interests. Alarm at the rupture of a decades-old partnership runs throughout.', updated_at = NOW() WHERE id = 'trade_european_defence';
UPDATE narratives_v2 SET claim_en = 'Chinese state framing presents the commercial relationship as large, complementary and expanding — record Chinese vehicle sales in Australia, solar and energy-transition cooperation, growing beef and agricultural exports, rising Australian public opinion of China. Tariff steps are presented as the routine operation of agreed quota thresholds administered by MOFCOM rather than pressure, with strategic-rivalry politics cast as the thing putting the relationship at risk.', updated_at = NOW() WHERE id = 'trade_mutual_benefit';
UPDATE narratives_v2 SET claim_en = 'America-First framing (US conservative press) holds that decades of European trade surpluses, non-tariff barriers, VAT and digital taxes have exploited the United States, and that tariffs are a legitimate, overdue tool to force fair terms and reindustrialise America. Europe is cast as a freeloading partner that must open its market or pay.', updated_at = NOW() WHERE id = 'trade_us_tariffs_justified';
UPDATE narratives_v2 SET claim_en = 'Rift-exploitation framing (Russian and Chinese state media) presents the tariff war not by taking Europe''s or Washington''s side but as proof that the US treats its "allies" as vassals to be milked, that European submission is humiliating, and that the transatlantic economic bond is fracturing to the benefit of a multipolar world. Schadenfreude at Western disunity, not endorsement of either side.', updated_at = NOW() WHERE id = 'trade_western_vassalage';
UPDATE narratives_v2 SET claim_en = 'Turkish state desk framing: investigations and trials against CHP officials, the Imamoglu indictment, and detentions of opposition mayors are legitimate anti-corruption proceedings handled by independent courts. Western press and pro-FETÖ commentary frame routine legal action as political persecution to delegitimise the elected government. Prescription: respect Turkish judicial sovereignty, reject foreign meddling in domestic legal process.', updated_at = NOW() WHERE id = 'turkey_anti_graft_legalism_defense';
UPDATE narratives_v2 SET claim_en = 'Western liberal coverage, especially the DACH cohort, frames the Imamoglu trial, mass CHP detentions, journalist arrests, and crackdown on opposition mayors as the dismantling of Turkish democracy — an Erdogan move to neutralise his strongest 2028 challenger and consolidate one-man rule. Evidence: indictment without robust public evidence, judicial composition concerns, social media restrictions on protest coverage, press card revocations. Prescription: EU/E3 pressure, conditional cooperation, support for Turkish civil society and independent press.', updated_at = NOW() WHERE id = 'turkey_authoritarian_drift_critique';
UPDATE narratives_v2 SET claim_en = 'EU and E3 (Germany, France, UK) coverage frames Turkey as a partner requiring calibrated rather than confrontational engagement. Position is genuinely two-sided: cooperate on migration, energy, Black Sea security, NATO eastern flank AND continue to flag democratic backsliding around the Imamoglu trial, journalist arrests, Cyprus and Aegean disputes. Prescription: sustained dialogue, conditional support, no rupture, no normalisation of backsliding.', updated_at = NOW() WHERE id = 'turkey_eu_engagement_pragmatic';
UPDATE narratives_v2 SET claim_en = 'Pro-Turkey publishers frame Erdogan''s Turkey as an independent middle power earning regional stature through balanced diplomacy across Gaza, Iran, Ukraine, Egypt, and the Gulf. Prescription: respect Turkey''s autonomous foreign policy stance within NATO, accept Turkic Council and Organization of Turkic States as legitimate spheres of influence, treat Ankara as indispensable on Gaza, Iran, Ukraine and Black Sea questions.', updated_at = NOW() WHERE id = 'turkey_independent_middle_power';
UPDATE narratives_v2 SET claim_en = 'Pro-Turkey and pan-Arab publishers frame Erdogan''s simultaneous channels to Trump, Putin, Pezeshkian, Zelensky, Sisi, and the Gulf as exactly the convening capacity the region needs. The Istanbul venue for Iran-US talks, Gaza peace board membership, Astana process continuity, grain corridor history, Egypt rapprochement all evidence Turkey''s indispensable role. Prescription: international acceptance of Turkey''s mediator role, no exclusion from regional settlements.', updated_at = NOW() WHERE id = 'turkey_legitimate_broker';
UPDATE narratives_v2 SET claim_en = 'Israeli right, Greek-Cypriot, and Fox-News-style framing: Erdogan plays every side — Hamas patron while courting the Gaza peace board, NATO member while opposing US-Israel Iran action, Ukraine ally while preserving Russian energy and tourism ties. The "mediator" framing is a vanity project that buys influence without delivering deliverables. Prescription: refuse to legitimise Turkish mediation; treat parallel channels as evidence of unreliability.', updated_at = NOW() WHERE id = 'turkey_two_faced_opportunist';
UPDATE narratives_v2 SET claim_en = 'Israeli right and hawkish-US commentary frame Erdogan''s Turkey as a hostile or at best unreliable NATO partner: courting Russia, opposing US-Israel Iran action, hosting Hamas leadership, undermining EU accession criteria, refusing to follow alliance line. Prescription: condition NATO defence cooperation on Turkey''s alignment, treat Erdogan rhetoric as adversarial signaling.', updated_at = NOW() WHERE id = 'turkey_unreliable_ally_warning';
UPDATE narratives_v2 SET claim_en = 'Israeli right and hawkish-US framing: by publicly opposing US-Israel strikes on Iran, telling Putin Turkey is against attacks on Iran, and offering Istanbul as a US-Iran venue, Erdogan is shielding the Iranian regime from accountability; NATO solidarity should be unequivocal. Prescription: confront Turkey''s Iran posture; condition NATO defence cooperation on alignment with the Iran-isolation policy.', updated_at = NOW() WHERE id = 'turkey_wrong_side_on_iran';
UPDATE narratives_v2 SET claim_en = 'Ukrainian maximalist framing (Ukrainian press + Western mainstream + Eastern European hawks + EU centrists, with internal disagreement chiefly from Hungary and Slovakia) holds that just peace requires full Russian withdrawal to internationally recognised 1991 borders, NATO accession or equivalent binding security guarantees, accountability mechanisms for war crimes, and reparations funded through seized Russian sovereign assets. Coverage rejects any framework that legitimises territorial losses, frames the 2014 Crimea precedent as proof that frozen conflicts invite further aggression, and emphasises Ukrainian society''s rejection of compromise terms. Prescription: continue military pressure until Russian retreat; refuse settlement frameworks that recognise annexations; pre-condition negotiations on Russian withdrawal.', updated_at = NOW() WHERE id = 'ukrainian_maximalist_peace';
UPDATE narratives_v2 SET claim_en = 'Western, allied and specialist coverage of a genuinely close contest: Chinese models reaching the frontier at lower cost, Chinese firms competing for US users, and rivals on both sides using every available tactic — blacklisting, litigation, restricted access, and accusations of distillation and illicit model access. Treated as commercial and strategic competition rather than as a question of principle.', updated_at = NOW() WHERE id = 'us_china_ai_lead_contest';
UPDATE narratives_v2 SET claim_en = 'Chinese state media framing of the AI contest as one Beijing is winning fairly and Washington is losing badly: achievements attributed to domestic research investment, US theft and distillation accusations rejected as smears, and defence blacklisting of Chinese technology firms presented as competition policy conducted by other means.', updated_at = NOW() WHERE id = 'us_china_ai_suppression';
UPDATE narratives_v2 SET claim_en = 'Western, allied and specialist coverage treating export controls as the instrument protecting a lead with direct military relevance: entity-list additions, licensing conditions on Nvidia sales, enforcement against diversion and smuggling, and allied alignment on lithography.', updated_at = NOW() WHERE id = 'us_china_export_control_necessity';
UPDATE narratives_v2 SET claim_en = 'Western, allied and industry coverage treating Chinese dominance of rare-earth mining, refining and magnet production as a live strategic exposure — hence the stockpile programme, Pentagon offtake deals, allied minerals pacts with the EU and Japan, and support for non-Chinese producers. The rare-earth truce is read as temporary relief, not a settlement.', updated_at = NOW() WHERE id = 'us_china_minerals_dependence_risk';
UPDATE narratives_v2 SET claim_en = 'Chinese state media framing of export licensing for rare earths as normal, lawful regulation of dual-use materials rather than coercion, and of US- and EU-led minerals alliances as exclusive blocs that fragment global trade. China''s processing dominance is presented as earned industrial capability, not as a weapon.', updated_at = NOW() WHERE id = 'us_china_minerals_lawful_leverage';
UPDATE narratives_v2 SET claim_en = 'Western and allied coverage treating the Beijing summit and the follow-on invitation as a working stabilisation of the relationship: tariff reductions, restored farm and aircraft purchases, an agreed AI dialogue and guardrails, and a resumption of leader-level contact after years of drift. The claim is not that rivalry has ended but that it is being managed.', updated_at = NOW() WHERE id = 'us_china_summit_engagement_works';
UPDATE narratives_v2 SET claim_en = 'The stance-bearing strand of Russian state coverage of US-China leader diplomacy: attention to moments where Xi rebuffs, needles or raises his voice at the US president, to Trump cast as the supplicant, to the Thucydides trap, and to Moscow-Beijing alignment reaffirmed immediately after the summit. It is third-party framing — neither an endorsement of the US position nor of China''s cooperation message — and sits on its own axis rather than the summit''s success/failure axis. Note that most Russian agency copy on this story is plain reportage carrying no stance, and is deliberately excluded by the framing gate.', updated_at = NOW() WHERE id = 'us_china_summit_multipolar_framing';
UPDATE narratives_v2 SET claim_en = 'Chinese state media framing of the summit as vindication of its preferred model for the relationship: major-power relations conducted on mutual respect and equality, "win-win" economic ties, and a rejection of rivalry as the organising frame. It is a counter to the Western competition consensus rather than a report on deliverables — the argument is that containment, export controls and tariffs are the anomaly and cooperation the norm.', updated_at = NOW() WHERE id = 'us_china_summit_new_chapter';
UPDATE narratives_v2 SET claim_en = 'Western and allied coverage — including US domestic critics across the political spectrum — reading the same summit as a poor return: no confirmed deals, commitments described by Beijing as preliminary, no movement on Iran or Taiwan, and a US president who conceded a state visit for atmospherics. This is the friendly-critic stance: the outlets voicing it are the same ones that report the engagement case, so publisher cannot separate them.', updated_at = NOW() WHERE id = 'us_china_summit_weak_hand';
UPDATE narratives_v2 SET claim_en = 'Western and allied coverage arguing that tariff pressure and Section 301 probes are the instrument that produced results — reciprocal tariff reductions, renewed US beef and soybean access, an aircraft order — and that they answer a durable trade deficit, subsidised overcapacity and restricted market access.', updated_at = NOW() WHERE id = 'us_china_tariff_leverage';
UPDATE narratives_v2 SET claim_en = 'Western business and mainstream coverage — and US industry itself — arguing that the tariff campaign imposes costs at home, injects legal and planning uncertainty after the Supreme Court ruling, and strengthens Beijing''s hand: automakers pressing to keep or lift restrictions on their own terms, farm exporters exposed to retaliation, and allies hedging toward China. Same publisher bloc as the leverage stance, so framing separates them.', updated_at = NOW() WHERE id = 'us_china_tariff_self_harm';
UPDATE narratives_v2 SET claim_en = 'Chinese state media framing of export controls as suppression of a competitor''s legitimate development rather than as security policy: curbs on Chinese entities opposed as overreach, warnings that the measures disrupt global chip supply chains, and emphasis on domestic substitution proceeding regardless. Beijing''s own refusal of cleared H200 imports is presented as leverage rather than dependence.', updated_at = NOW() WHERE id = 'us_china_tech_containment';
UPDATE narratives_v2 SET claim_en = 'Chinese state media framing of tariffs and Section 301 probes as unilateralism and abuse of process rather than as a response to any imbalance: measures taken outside the multilateral system, harmful to all parties, and aimed at suppressing a competitor.', updated_at = NOW() WHERE id = 'us_china_trade_unilateralism';
UPDATE narratives_v2 SET claim_en = 'Coverage of rulings that constrained the administration -- birthright citizenship upheld, the global tariff order struck down, a Federal Reserve governor kept in office, mail-ballot orders enjoined -- read as evidence that judicial review still functions.', updated_at = NOW() WHERE id = 'usdom_courts_checks_hold';
UPDATE narratives_v2 SET claim_en = 'Coverage of the other half of the docket -- removal power upheld, immigration discretion expanded, emergency-docket orders issued without full argument, state policies overridden -- and of a court whose composition and procedure are themselves now contested.', updated_at = NOW() WHERE id = 'usdom_courts_deference';
UPDATE narratives_v2 SET claim_en = 'Coverage documenting mid-cycle redistricting races between states, the Voting Rights Act narrowed, mail-ballot restrictions struck down and reimposed, proof-of-citizenship bills, an FBI raid on a voting-rights group, and open discussion of how an incumbent might tilt a midterm.', updated_at = NOW() WHERE id = 'usdom_electoral_franchise_threat';
UPDATE narratives_v2 SET claim_en = 'Coverage presenting voter-ID requirements, proof-of-citizenship rules, voter-roll maintenance and limits on mail balloting as ordinary safeguards against fraud, and redistricting as a lawful power of elected state legislatures.', updated_at = NOW() WHERE id = 'usdom_electoral_integrity_case';
UPDATE narratives_v2 SET claim_en = 'Wire, international and US coverage treating the document releases, depositions and contempt votes as an accountability process that is working: names are surfacing across both parties and across borders, witnesses are being compelled to testify, and figures long thought untouchable are being questioned, charged or forced to resign.', updated_at = NOW() WHERE id = 'usdom_epstein_accountability';
UPDATE narratives_v2 SET claim_en = 'Coverage arguing the release process is being controlled to protect the powerful: files redacted or withheld, testimony taken behind closed doors, the attorney general accused of shielding names, witnesses pleading the Fifth, and briefings dismissed as theatre.', updated_at = NOW() WHERE id = 'usdom_epstein_obstruction';
UPDATE narratives_v2 SET claim_en = 'Coverage of the pressure side of the same story -- an attempt to remove a sitting governor blocked in court, a criminal referral against the chair later dropped, public demands that he resign, a chair warning the institution is under a stress test and that lost credibility is hard to restore.', updated_at = NOW() WHERE id = 'usdom_fed_capture_risk';
UPDATE narratives_v2 SET claim_en = 'Business and wire coverage treating the chair nomination and Senate confirmation as an ordinary handover -- a nominee clearing committee, an incumbent serving out his term, the board continuing to set policy on its own reading of inflation -- and stressing that the legal architecture of independence has held.', updated_at = NOW() WHERE id = 'usdom_fed_orderly_succession';
UPDATE narratives_v2 SET claim_en = 'Coverage documenting deaths and illness in detention, arrests without warrants, detained children and elderly people, long-resident and legally present people swept up, judges ordering releases, and the chilling effect on schools, clinics and workplaces.', updated_at = NOW() WHERE id = 'usdom_ice_due_process';
UPDATE narratives_v2 SET claim_en = 'Coverage presenting interior enforcement as lawful execution of immigration statute and an electoral mandate: removals of people with criminal records, funding votes in Congress, court wins expanding executive discretion, and officers portrayed as targeted by violence.', updated_at = NOW() WHERE id = 'usdom_ice_enforcement_mandate';
UPDATE narratives_v2 SET claim_en = 'Coverage treating the incidents as a pattern rather than isolated events: repeated attempts against a president, a member of Congress attacked at a town hall, judges reporting threats and requiring heightened security, polling showing large numbers disbelieve official accounts, and warnings about the climate that produces this.', updated_at = NOW() WHERE id = 'usdom_violence_climate';
UPDATE narratives_v2 SET claim_en = 'Coverage centred on the security response and the prosecutions: agents returning fire and evacuating principals, a suspect identified and charged, a plot against a public event foiled, and officials thanking their details.', updated_at = NOW() WHERE id = 'usdom_violence_protective_response';
UPDATE narratives_v2 SET claim_en = 'Indian, Turkish and wider Global South coverage treating the waivers less as American generosity than as confirmation that the restrictions were unenforceable: purchases continued through every phase, energy security is a sovereign decision, and Washington relaxes or tightens the rules according to its own needs.', updated_at = NOW() WHERE id = 'us_russia_buyer_autonomy';
UPDATE narratives_v2 SET claim_en = 'Western mainstream coverage treating the restored contacts -- envoy trips, the resumed high-level military channel, foreign-minister phone calls -- as the ordinary machinery of great-power management: without it there is no route to a settlement, no deconfliction, and no arms-control conversation. This position is held widely but stated rarely: Western outlets overwhelmingly present these contacts as Ukraine-war developments, so the argument for engagement is usually implicit in war reporting rather than made as bilateral commentary. The card is small by construction, not for want of coverage.', updated_at = NOW() WHERE id = 'us_russia_engagement_necessary';
UPDATE narratives_v2 SET claim_en = 'Western mainstream and arms-control coverage treating the February 2026 lapse of the last US-Russia warhead limits as a genuine loss — the end of inspections and data exchange, the removal of predictability — and reporting proposals for a replacement pact as a necessary corrective rather than a concession.', updated_at = NOW() WHERE id = 'us_russia_new_treaty_needed';
UPDATE narratives_v2 SET claim_en = 'Western mainstream, transatlantic-critical and Ukrainian coverage arguing that summitry and warm bilateral atmospherics -- congratulation calls, G20 invitations, talk of joint investment projects -- grant Moscow the status of an equal partner it has not earned, and that decisions about European security are being taken over Europe''s and Kyiv''s heads. As with the engagement stance, this objection is mostly voiced inside Ukraine-war coverage rather than as commentary on the bilateral relationship, which is why it registers here at a fraction of the volume the Kremlin''s own account of that relationship achieves. Same publisher bloc as the engagement stance, so framing separates them.', updated_at = NOW() WHERE id = 'us_russia_normalisation_premature';
UPDATE narratives_v2 SET claim_en = 'Western mainstream and business coverage arguing that waivers on Russian crude were forced by supply conditions — the Iran war, stranded cargoes, refiners and importers such as India needing barrels — and that keeping oil flowing while retaining the legal architecture of sanctions is the responsible course.', updated_at = NOW() WHERE id = 'us_russia_relief_pragmatic';
UPDATE narratives_v2 SET claim_en = 'Western mainstream, transatlantic-critical and Ukrainian coverage arguing that the waivers transfer billions to the Russian budget while the war continues, that they were granted without reciprocal concessions, and that they split the US from European and British partners still tightening enforcement. Same publisher bloc as the pragmatic stance, so framing separates them.', updated_at = NOW() WHERE id = 'us_russia_relief_rewards_moscow';
UPDATE narratives_v2 SET claim_en = 'Russian state coverage framing the waivers as proof that restrictions on Russian energy were always unworkable: the world market needs Russian barrels, buyers keep buying, and the US has quietly conceded the point while continuing to demand that Europe bear the cost of containment. Sanctions are cast as illegitimate extraterritorial coercion rather than lawful policy.', updated_at = NOW() WHERE id = 'us_russia_sanctions_illegitimate';
UPDATE narratives_v2 SET claim_en = 'Western hawkish, defence-policy and Ukrainian coverage arguing that arms control has become one-sided: Russia has fielded novel systems outside any treaty''s scope, verification had already collapsed in practice, and a successor pact negotiated from weakness would constrain US modernisation and missile defence while legitimising Moscow. Same publisher bloc as the successor-treaty stance, so framing separates them.', updated_at = NOW() WHERE id = 'us_russia_treaty_constrains_only_us';
UPDATE narratives_v2 SET claim_en = 'Russian state coverage attributing the collapse of the strategic framework to Washington: post-New START proposals were rejected, the Golden Dome missile-defence programme undermines mutual vulnerability, and Moscow presents itself as willing to observe limits if the US does the same. Novel Russian systems are framed as responses to that programme rather than as its cause.', updated_at = NOW() WHERE id = 'us_russia_us_buildup_drives_race';
UPDATE narratives_v2 SET claim_en = 'Russian state coverage in its adversarial register: the channel exists but Washington stalls, issues ultimatums, drifts from the mediator role it claimed, presses Europe to carry the cost of containment, and pursues Russian companies commercially while talking cooperation. US policy is presented as unchanged in substance regardless of administration.', updated_at = NOW() WHERE id = 'us_russia_washington_bad_faith';
UPDATE narratives_v2 SET claim_en = 'Russian state coverage presenting the restored channel as overdue recognition that Russia cannot be isolated: the previous freeze is over, contacts are being rebuilt on a basis of equality, and Washington must respect Russian interests for cooperation to be mutually beneficial. Because Russian state media treat the bilateral relationship as a standing subject rather than an adjunct of the war, this framing is asserted directly and continuously, giving it far more standalone volume than any Western counter-position achieves.', updated_at = NOW() WHERE id = 'us_russia_washington_realism';
UPDATE narratives_v2 SET claim_en = 'EU / E3 / US shipping-desk mainstream: the Houthi problem is primarily a freedom-of-navigation problem requiring coalition naval pressure (Prosperity Guardian, Aspides) and a Gaza ceasefire that removes the Houthis'' stated casus belli; humanitarian impact in Yemen is a parallel concern, not the primary frame. Prescription: sustained coalition naval pressure, Gaza ceasefire diplomacy, humanitarian access; reject both kinetic escalation and unilateral concession.', updated_at = NOW() WHERE id = 'western_pragmatic_navigation';
UPDATE narratives_v2 SET claim_en = 'Systemic-alarm framing (Western mainstream + reformist Ukrainian press) treats high-level corruption cases -- reaching the Presidential Office and figures like Yermak -- as a threat to Ukraine credibility, Western aid, and EU accession, rather than proof that institutions work. Distinct from Russian-state endemic-corruption framing: it does not call the state illegitimate or aid categorically stolen, but expresses genuine concern from Ukraine supporters.', updated_at = NOW() WHERE id = 'western_systemic_alarm';
UPDATE narratives_v2 SET claim_en = 'Endemic-corruption framing (Russian state press + Western contrarian + Global South + some Hungarian-aligned EU) treats the same investigations and scandals as confirmation that the Zelensky inner circle is systemically corrupt, that Western aid is being stolen at scale through defense procurement, that the regime is increasingly authoritarian (banned opposition parties, restricted media, cancelled elections, Yermak-centred power concentration), and that EU/NATO accession on this institutional basis is unrealistic. Coverage uses the same anti-corruption agency investigations as evidence of scale, frames prosecutions as theatrical or selective, and emphasises Western media protection of the regime. Prescription: condition or halt aid pending genuine accountability; recognise that the regime cannot deliver promised reforms; reject any settlement that consolidates the current Kyiv leadership.', updated_at = NOW() WHERE id = 'zelensky_regime_corruption';

COMMIT;
